metrics={r['lepton']:r for r in rows('tables/charged_lepton_qed_closure_metrics_v49.csv')}; audit={r['layer']:r for r in rows('tables/charged_lepton_qed_closure_audit_v49.csv')}; ledger={r['entry']:r for r in rows('tables/charged_lepton_qed_boundary_required_ledger_v49.csv')}; forbidden={r['forbidden_input']:r for r in rows('tables/charged_lepton_qed_forbidden_inputs_v49.csv')}; case={r['sector']:r for r in rows('tables/trace_to_scheme_case_table_v49.csv')}
alpha_inv=137.035999177; alpha_inv_unc=0.000000021; alpha=1/alpha_inv; alpha_unc=alpha_inv_unc/(alpha_inv**2); aopi=alpha/math.pi; lo_factor=1/(1+aopi); second=100*(aopi**2); third=100*(aopi**3)
phi=[0.5110026357885311,105.658243985342,1776.9168320084111]; refs=[0.51099895069,105.6583755,1776.86]; unc=[0.00000000016,0.0000023,0.12]
absres=[phi[i]-refs[i] for i in range(3)]; rel=[100*absres[i]/refs[i] for i in range(3)]; apf=100/5063; combined=math.sqrt(apf**2+second**2); ratios=[abs(x)/combined for x in rel]; lo_run=[x*lo_factor for x in phi]
for nd in ['Charged-Lepton QED Closure Boundary Theorem','final closure boundary','P_{\\rm full\\ QED\\ ledger\\ boundary}','No-smuggling closure','External-ledger boundary','P_{\\rm QED\\ running\\ final}','not an APF-side missing theorem']:
    check('tex_contains_'+nd[:40].replace(' ','_').replace('\\','bs'), nd in tex)
