for script in inherited: check('inherited_exists_'+script,(ROOT/'scripts'/script).exists())
passed=sum(ok for _,ok in checks); total=len(checks)
for name,ok in checks: print(('PASS' if ok else 'FAIL'),name)
print(f'Total checks: {passed}/{total}')
if passed!=total or total!=j.get('checks_total'): raise SystemExit(1)
print('CHARGED_LEPTON_QED_CLOSURE_BOUNDARY_THEOREM_PASS')
